// // This module handles two interrupt signals (IRQ1 and IRQ2). When both interrupts are deasserted, the controller sets an output signal (IRQ_OUT) high. The controller also has a reset signal which, when deasserted, should clear the IRQ_OUT signal.
module interrupt_controller(  
    input wire clk,  
    input wire reset,  
    input wire IRQ1,  
    input wire IRQ2,  
    output reg IRQ_OUT  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            IRQ_OUT <= 0;  
        end else begin  
            IRQ_OUT <= IRQ1 | IRQ2;  
        end  
    end  
endmodule
